import re

def check_password_strength(password: str) -> dict:
    """Checks the strength of a given password against a set of predefined rules.

    Args:
        password: The password string to check.

    Returns:
        A dictionary containing the calculated strength score and a list of failed rule IDs.
    """
    score = 0
    failed_rules = []

    # Define password strength rules
    # Each rule has an ID, a description, and a boolean check function.
    # The check function takes the password string as an argument.
    rules = [
        {
            "id": "BR-001",
            "description": "Password must be at least 8 characters long",
            "check": lambda p: len(p) >= 8
        },
        {
            "id": "BR-002",
            "description": "Password must contain at least one uppercase letter",
            "check": lambda p: bool(re.search(r'[A-Z]', p))
        },
        {
            "id": "BR-003",
            "description": "Password must contain at least one lowercase letter",
            "check": lambda p: bool(re.search(r'[a-z]', p))
        },
        {
            "id": "BR-004",
            "description": "Password must contain at least one digit",
            "check": lambda p: bool(re.search(r'\d', p)) # Implemented BR-004 using regex
        },
        {
            "id": "BR-005",
            "description": "Password must contain at least one special character",
            "check": lambda p: bool(re.search(r'[!@#$%^&*(),.?":{}|<>]', p))
        },
    ]

    # Iterate through rules, update score and failed_rules list
    for rule in rules:
        if rule["check"](password):
            score += 1
        else:
            failed_rules.append(rule["id"])

    return {
        "score": score,
        "failed_rules": failed_rules
    }
